31	  int rnti = 13;
32	  f1_ue_data_t data = {.secondary_ue = 1};
33	  bool ret = du_add_f1_ue_data(rnti, &data);
34	  DevAssert(ret);
35	  ret = du_add_f1_ue_data(rnti, &data);
36	  DevAssert(!ret);
37	  bool exists = du_exists_f1_ue_data(rnti);
38	  DevAssert(exists);
39	  f1_ue_data_t rdata = du_get_f1_ue_data(rnti);
40	  DevAssert(rdata.secondary_ue == data.secondary_ue);
41	}
