43	void cu_data_test()
44	{
45	  cu_init_f1_ue_data();
46	  int ue_id = 13;
47	  f1_ue_data_t data = {.secondary_ue = 1};
48	  bool ret = cu_add_f1_ue_data(ue_id, &data);
49	  DevAssert(ret);
50	  ret = cu_add_f1_ue_data(ue_id, &data);
51	  DevAssert(!ret);
52	  data.secondary_ue = 2;
53	  ret = cu_update_f1_ue_data(ue_id, &data);
54	  bool exists = cu_exists_f1_ue_data(ue_id);
55	  DevAssert(exists);
56	  f1_ue_data_t rdata = cu_get_f1_ue_data(ue_id);
57	  DevAssert(rdata.secondary_ue == data.secondary_ue);
58	
59	  rdata.secondary_ue = 3;
60	  // overwrite once more
61	  ret = cu_update_f1_ue_data(ue_id, &rdata);
62	  DevAssert(ret);
63	  exists = cu_exists_f1_ue_data(ue_id);
64	  DevAssert(exists);
65	  f1_ue_data_t r2data = cu_get_f1_ue_data(ue_id);
66	  DevAssert(r2data.secondary_ue == rdata.secondary_ue);
67	}
68	
69	int main()
70	{
71	  du_data_test();
72	  cu_data_test();
73	  return 0;
74	}

